@ARTICLE{10.3390/ijms27031440,
	author = {Wu H(1) and Xu X(1) and Chen J(2) and Morisseau C(3) and Hammock BD(3) and Tseng YH(4) and Zhao L(1).},
	title = {Transplantation of Soluble Epoxide Hydrolase Inhibitor-Treated Human Brown Adipocytes Promotes Adipose Tissue Activation in High-Fat-Diet-Fed Nude Mice.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Brown adipose tissue (BAT) plays a key role in non-shivering thermogenesis and is a promising target for enhancing energy expenditure to combat obesity. Soluble epoxide hydrolase (sEH) is a cytosolic enzyme that catalyzes the conversion of epoxy fatty acids into less active diols. We have reported that local administration of the sEH inhibitor, t-TUCB, to the endogenous interscapular BAT (iBAT) of diet-induced obese mice decreased serum triglycerides and enhanced the expression of essential genes associated with lipid metabolism. Here, the effects of sEH inhibition by t-AUCB were assessed on human brown adipocyte (HuBr) differentiation and in nude mice transplanted with t-AUCB-treated HuBr. HuBr cells were differentiated with t-AUCB (1-10 μM) or the vehicle (0.1% DMSO). HuBr differentiated with t-AUCB at 5 μM (AUCB 5) or DMSO was mixed with matrix gel and transplanted into the nude mice. The mice were then fed a high-fat diet for eight weeks. The mice receiving AUCB 5-treated HuBr exhibited markedly reduced lipid accumulation in the iBAT compared with DMSO or matrix-only controls, along with increased protein expression of thermogenic PGC1α and UCP1, fatty acid transporter CD36, and CPT1A in the iBAT, while the NFκB inflammatory pathways were suppressed in both the AUCB 5 and DMSO groups. Moreover, the PGC1α and CPT1A protein levels were elevated, and the adipocyte sizes were decreased in the epididymal white adipose tissue of the AUCB 5 group. Our findings indicate that the transplantation of HuBr treated with AUCB 5 may stimulate thermogenesis, enhance lipid metabolism, and reduce inflammation in iBAT.},
	doi = {10.3390/ijms27031440},
	pmid = {41683861 [Indexed for MEDLINE]},
	note = {PMC12898555}
}

@ARTICLE{10.3390/ijms27031306,
	author = {Sobczyński J(1), Nowaczyński F(1)(2), Smolińska K(3) and Lachowicz-Radulska J(1) and Serefko A(1) and Szopa A(1).},
	title = {Natural Bioactive Compounds Targeting FABP4 in Adipogenesis and Obesity: Evidence from In Vitro and In Vivo Studies.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {FABP4 (fatty acid-binding protein 4) is a lipid chaperone and secreted adipokine linking dysregulated fatty acid handling with inflammation, cellular stress, and insulin resistance in obesity. By modulating nuclear receptor signaling (notably PPARγ) and enhancing NF-κB/MAPK activation in adipocytes and macrophages, FABP4 contributes to maladaptive adipose remodeling and systemic metabolic decline. This review critically summarizes recent preclinical evidence on natural bioactive compounds that regulate FABP4 expression and associated adipogenic programs in models of adipogenesis and diet-induced obesity. Data from 3T3-L1/OP9 adipocytes, rodent studies, and selected alternative models indicate that many plant-derived extracts and phytochemicals (e.g., polyphenols, saponins, coumarins, terpenoids, and fermented products) down-regulate FABP4 at mRNA and/or protein levels. These effects are frequently accompanied by suppression of PPARγ/C/EBPα/SREBP1c signaling, activation of AMPK-related pathways, reduced lipid accumulation, and improved metabolic outcomes including lower weight gain, reduced adipocyte hypertrophy, improved steatosis, and favorable serum lipid profiles. Natural compounds from non-plant sources (animal- and microbe-derived metabolites) further broaden FABP4-targeting strategies, supporting FABP4 as a cross-class therapeutic node. Key translational barriers include poor extract standardization, incomplete identification of active constituents, limited oral bioavailability, microbiome-dependent variability, and scarce clinical validation. Future work should prioritize well-characterized lead scaffolds, targeted delivery, rational combinations, and standardized, adequately powered clinical trials assessing dose, durability of FABP4 suppression, and cardiometabolic safety.},
	doi = {10.3390/ijms27031306},
	pmid = {41683732 [Indexed for MEDLINE]},
	note = {PMC12898738}
}

@ARTICLE{10.3390/ijms27031186,
	author = {Ábel T(1) and Csobod Csajbókné É(1).},
	title = {Semaglutide-Mediated Remodeling of Adipose Tissue in Type 2 Diabetes: Molecular Mechanisms Beyond Glycemic Control.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Type 2 diabetes mellitus (T2DM) is characterized not only by chronic hyperglycemia but also by profound adipose tissue dysfunction, including impaired lipid handling, low-grade inflammation, mitochondrial dysfunction, and extracellular matrix (ECM) remodeling. These adipose tissue alterations play a central role in the development of systemic insulin resistance, ectopic lipid accumulation, and cardiometabolic complications. Glucagon-like peptide-1 receptor agonists (GLP-1RAs), particularly semaglutide, have emerged as highly effective therapies for T2DM and obesity. While their glucose-lowering and appetite-suppressive effects are well established, accumulating evidence indicates that semaglutide exerts pleiotropic metabolic actions that extend beyond glycemic control, with adipose tissue representing a key target organ. This review synthesizes current preclinical and clinical evidence on the molecular and cellular mechanisms through which semaglutide modulates adipose tissue biology in T2DM. We discuss depot-specific effects on visceral and subcutaneous adipose tissue, regulation of adipocyte lipid metabolism and lipolysis, enhancement of mitochondrial biogenesis and oxidative capacity, induction of beige adipocyte programming, modulation of adipokine and cytokine secretion, immunometabolic remodeling, and attenuation of adipose tissue fibrosis and ECM stiffness. Collectively, available data indicate that semaglutide promotes a functional shift in adipose tissue from a pro-inflammatory, lipid-storing phenotype toward a more oxidative, insulin-sensitive, and metabolically flexible state. These adipose-centered adaptations likely contribute to improvements in systemic insulin sensitivity, reduction in ectopic fat deposition, and attenuation of cardiometabolic risk observed in patients with T2DM. Despite compelling mechanistic insights, much of the current evidence derives from animal models or in vitro systems. Human adipose tissue-focused studies integrating molecular profiling, advanced imaging, and longitudinal clinical data are therefore needed to fully elucidate the extra-glycemic actions of semaglutide and to translate these findings into adipose-targeted therapeutic strategies.},
	doi = {10.3390/ijms27031186},
	pmid = {41683613 [Indexed for MEDLINE]},
	note = {PMC12898281}
}

@ARTICLE{10.3390/nu18030401,
	author = {He X(1) and Liu Y(1) and Cui S(1) and Yu Z(2) and He Z(1) and Zong Y(1) and Chen W(1) and Geng J(1) and Zhou J(1) and Li Z(1) and Zhao Y(1)(3) and Teng H(1)(3).},
	title = {Research on the Therapeutic Effect and Mechanism of Stir-Roasted Deer Velvet Antler with Ghee on Non-Alcoholic Fatty Liver Disease.},
	journal = {Nutrients},
	year = {2026},
	abstract = {Objectives: This study aims to explore the therapeutic effect and mechanism of stir-roasted deer velvet antler with ghee (ZLR) on Non-Alcoholic Fatty Liver Disease (NAFLD). Methods: This study used proteomics to analyze the protein composition of roasted deer antler velvet. It established a high-fat diet (HFD)-induced NAFLD rat model and evaluated the therapeutic effects of different dosage groups, including liver injury, oxidative stress, glucose metabolism, steatosis, and insulin homeostasis (via fasting glucose tolerance). Transcriptomics explored the mechanism. Gene expression and Western blot detected lipid metabolism-related gene expression. In vivo experiments validated that ZLR-containing serum alleviates NAFLD and reduces reactive oxygen species levels. Results: The results indicated that ZLR could significantly reduce the body weight, liver weight and degree of hepatic steatosis in HFD rats, improve glycolipid metabolism and insulin sensitivity, and alleviate oxidative stress damage. The mechanism involves activating the adenosine monophosphate-activated protein kinase/peroxisome proliferator-activated receptor (AMPK/PPAR) signaling pathway, regulating the expression of lipid metabolism-related genes, promoting fatty acid oxidation, and reducing fat deposition. The results of in vitro experiments show that ZLR-containing serum can effectively reduce lipid droplet production in liver cells and effectively alleviate oxidative stress damage in liver cells. Conclusions: The traditional Chinese medicine processed product ZLR can regulate lipid metabolism in the body and alleviate the degree of NAFLD by activating the AMPK and PPAR signaling pathways. It provides new ideas for the clinical treatment of NAFLD.},
	doi = {10.3390/nu18030401},
	pmid = {41683224 [Indexed for MEDLINE]},
	note = {PMC12899000}
}

